const express = require('express');
const app = express();

// load a plugin from an environment variable
if (process.env.PLUGIN_PATH) {
  const pluginPath = process.env.PLUGIN_PATH;
  require(pluginPath)(app); // pass the Express instance to allow for route and middleware registration
} else {
  console.log('No PLUGIN_PATH provided');
}

// start the server
const port = 3000;
app.listen(port, () => console.log(`Server running on http://localhost:${port}/`));